// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-disponibilidad

const input = $input.first().json;

// Extraer datos
const fecha_cita = input.fecha_cita;
const hora_cita = input.hora_cita;
const taller_cita = input.taller_cita;

// VALIDACIONES
const errores = [];

// 1. VALIDAR FECHA (YYYY-MM-DD)
const regexFecha = /^\d{4}-\d{2}-\d{2}$/;
if (!fecha_cita || !regexFecha.test(fecha_cita)) {
  errores.push(`Fecha inválida: "${fecha_cita}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// 2. VALIDAR HORA (HH:MM)
const regexHora = /^\d{2}:\d{2}$/;
if (!hora_cita || !regexHora.test(hora_cita)) {
  errores.push(`Hora inválida: "${hora_cita}". Formato requerido: HH:MM (ej: 10:30)`);
}

// Validar que sea uno de los 10 turnos válidos
const turnosValidos = [
  "08:00", "08:15", "08:30", "08:45",
  "09:00", "09:15", "09:30", "09:45",
  "10:00", "10:15","10:30"
];
if (hora_cita && !turnosValidos.includes(hora_cita)) {
  errores.push(`Hora no permitida: "${hora_cita}". Solo se aceptan turnos: ${turnosValidos.join(', ')}`);
}

// 3. VALIDAR TALLER (valores exactos)
const talleresValidos = [
  "Nissan - Tucuman",
  "Nissan - Santiago del Estero"
];
if (!taller_cita || !talleresValidos.includes(taller_cita)) {
  errores.push(`Taller inválido: "${taller_cita}". Valores permitidos: "${talleresValidos[0]}" o "${talleresValidos[1]}"`);
}

// SI HAY ERRORES: Detener ejecución y retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        fecha_cita,
        hora_cita,
        taller_cita
      }
    }
  }];
}

// SI TODO OK: Pasar datos validados
return [{
  json: {
    success: true,
    fecha_cita,
    hora_cita,
    taller_cita
  }
}];

// PROCESAR DISPONIBILIDAD Y GENERAR RESPUESTA

// Datos de entrada
const trigger = $('trigger-disponibilidad').first().json;
const httpResponse = $input.first().json;

const fechaSolicitada = trigger.fecha_cita;
const horaSolicitada = trigger.hora_cita;
const tallerSolicitado = trigger.taller_cita;

// Todos los turnos posibles del día (cada 15 min de 08:00 a 10:15)
const TODOS_LOS_TURNOS = [
  "08:00", "08:15", "08:30", "08:45",
  "09:00", "09:15", "09:30", "09:45",
  "10:00", "10:15","10:30"
];

// Extraer citas del día desde la respuesta del CRM
const citasDelDia = httpResponse.InternalObject || [];

// Obtener solo las horas ocupadas (pueden haber duplicados)
const horasOcupadas = citasDelDia.map(cita => cita.HORA);
const horasOcupadasUnicas = [...new Set(horasOcupadas)]; // eliminar duplicados

// Calcular turnos disponibles
const turnosDisponibles = TODOS_LOS_TURNOS.filter(
  turno => !horasOcupadasUnicas.includes(turno)
);

// Verificar si el horario solicitado está disponible
const estaDisponible = !horasOcupadasUnicas.includes(horaSolicitada);

// Validar si la hora solicitada es válida
const esHoraValida = TODOS_LOS_TURNOS.includes(horaSolicitada);

// Generar mensaje descriptivo
let mensaje;
if (!esHoraValida) {
  mensaje = `La hora ${horaSolicitada} no es un turno válido. Turnos permitidos cada 15 min de 08:00 a 10:15.`;
} else if (estaDisponible) {
  mensaje = `✅ El horario ${horaSolicitada} está DISPONIBLE para el ${fechaSolicitada} en ${tallerSolicitado}.`;
} else {
  const alternativas = turnosDisponibles.slice(0, 3).join(", "); // primeras 3 opciones
  mensaje = `❌ El horario ${horaSolicitada} está OCUPADO. Horarios disponibles: ${alternativas}${turnosDisponibles.length > 3 ? '...' : ''}`;
}

// Preparar respuesta estructurada
const respuesta = {
  success: true,
  horario_solicitado: horaSolicitada,
  disponible: estaDisponible && esHoraValida,
  es_horario_valido: esHoraValida,
  fecha: fechaSolicitada,
  taller: tallerSolicitado,
  turnos_ocupados: horasOcupadasUnicas.sort(), // ordenados
  turnos_disponibles: turnosDisponibles,
  total_citas_dia: citasDelDia.length,
  total_turnos_ocupados: horasOcupadasUnicas.length,
  total_turnos_disponibles: turnosDisponibles.length,
  mensaje: mensaje,
  // Info adicional útil para el agente
  proximos_disponibles: turnosDisponibles.slice(0, 5), // top 5
  todas_las_citas: citasDelDia.map(c => ({
    hora: c.HORA,
    servicio: c.SERVICIO,
    doc_id: c.DOC_ID
  }))
};

return [{ json: respuesta }];

// En el nodo "salida_con_error" (Code node)
const errores = $input.first().json.errores || ["Error de validación"];

return [{
  json: {
    success: false,
    error: "VALIDACION_FALLIDA",
    errores: errores,
    disponible: false,
    mensaje: errores.join(", ")
  }
}];
